let added = 0;
for (const row of D3_SCHOOLS) {
  const [name, mascot, city, state, conference, lat, lng, zip, pub_priv, enrollment, tuition, acceptance_rate, graduation_rate, coach, coach_email, website, espn_id, high_academic, primary_color] = row;

  // Skip if already exists
  if (schools.find(s => s.name === name && s.division === "D3")) continue;

  let logo_url = null;
  if (espn_id) {
    logo_url = `https://a.espncdn.com/i/teamlogos/ncaa/500/${espn_id}.png`;
  } else if (website) {
    try {
      const domain = new URL(website).hostname;
      logo_url = `https://www.google.com/s2/favicons?domain=${domain}&sz=128`;
    } catch {}
  }

  schools.push({
    id: nextId++,
    name,
    mascot,
    city,
    state,
    zip,
    latitude: lat,
    longitude: lng,
    division: "D3",
    public_private: pub_priv,
    conference,
    current_ranking: null,
    tuition,
    instagram: null,
    x_account: null,
    head_coach_name: coach,
    head_coach_email: coach_email,
    assistant_coach_name: null,
    assistant_coach_email: null,
    website,
    created_at: "2026-02-19 00:00:00",
    last_season_record: null,
    logo_url,
    mlb_draft_picks: 0,
    stadium_latitude: lat,
    stadium_longitude: lng,
    stadium_name: null,
    stadium_image_url: null,
    enrollment,
    acceptance_rate,
    graduation_rate,
    cws_appearances: 0,
    ncaa_regionals: 0,
    roster_size: 40,
    scholarship_limit: 0,
    recruiting_questionnaire_url: null,
    nil_url: null,
    high_academic: high_academic || false,
    primary_color: primary_color || "#333333",
  });
  added++;
}

fs.writeFileSync(SCHOOLS_PATH, JSON.stringify(schools, null, 2) + "\n");
console.log(`Added ${added} D3 schools. Total schools: ${schools.length}`);

// Summary
const d3 = schools.filter(s => s.division === "D3");
const withCoach = d3.filter(s => s.head_coach_name).length;
const withLogo = d3.filter(s => s.logo_url).length;
const withWebsite = d3.filter(s => s.website).length;
console.log(`D3 stats: ${d3.length} schools, ${withCoach} with coaches, ${withLogo} with logos, ${withWebsite} with websites`);
